const src = `export function reconcileCoveredCosts(spreadsheetJson: string, parkFeeScheduleJson: string): { covered: { spreadsheetItem: string; feeScheduleItem: string; amount: number }[]; uniqueToSpreadsheet: string[]; uniqueToFeeSchedule: string[]; totalCovered: number; summary: string } {
  // cross-check spreadsheet line items against the Ngorongoro park fee schedule to flag covered / duplicate costs
  // Parses two JSON arrays — one for spreadsheet line items, one for park fee schedule entries —
  // and matches them by normalized name/substring overlap. Returns flagged duplicates and unique items.

  interface LineItem {
    name: string;
    amount: number;
    category?: string;
  }

  const spreadsheetItems: LineItem[] = JSON.parse(spreadsheetJson);
  const feeScheduleItems: LineItem[] = JSON.parse(parkFeeScheduleJson);

  const normalize = (s: string): string => s.toLowerCase().replace(/[^a-z0-9]/g, '');

  const covered: { spreadsheetItem: string; feeScheduleItem: string; amount: number }[] = [];
  const uniqueToSpreadsheet: string[] = [];
  const uniqueToFeeSchedule: string[] = [];
  const matchedFeeIndices = new Set<number>();

  for (const sItem of spreadsheetItems) {
    const sNorm = normalize(sItem.name);
    let found = false;
    for (let j = 0; j < feeScheduleItems.length; j++) {
      if (matchedFeeIndices.has(j)) continue;
      const fNorm = normalize(feeScheduleItems[j].name);
      // fuzzy match: one string contains the other or exact normalized match
      if (sNorm === fNorm || sNorm.includes(fNorm) || fNorm.includes(sNorm)) {
        covered.push({
          spreadsheetItem: sItem.name,
          feeScheduleItem: feeScheduleItems[j].name,
          amount: sItem.amount,
        });
        matchedFeeIndices.add(j);
        found = true;
        break;
      }
    }
    if (!found) {
      uniqueToSpreadsheet.push(sItem.name);
    }
  }

  for (let j = 0; j < feeScheduleItems.length; j++) {
    if (!matchedFeeIndices.has(j)) {
      uniqueToFeeSchedule.push(feeScheduleItems[j].name);
    }
  }

  const totalCovered = covered.reduce((sum, c) => sum + c.amount, 0);

  const summary = \`Reconciled \${covered.length} covered item(s) totalling \$${totalCovered.toFixed(2)}. \${uniqueToSpreadsheet.length} spreadsheet-only, \${uniqueToFeeSchedule.length} fee-schedule-only.\`;

  return { covered, uniqueToSpreadsheet, uniqueToFeeSchedule, totalCovered, summary };
}`;

